import{_ as e,o as t,c as l,a3 as i}from"./chunks/framework.gsMzR_Kb.js";const u=JSON.parse('{"title":"内容原则","description":"站点只收录无版权风险的原典、注解与个人解读。","frontmatter":{"title":"内容原则","description":"站点只收录无版权风险的原典、注解与个人解读。","category":"reference","aliases":["内容原则","收录原则","content policy"]},"headers":[],"relativePath":"standards/content-policy.md","filePath":"standards/content-policy.md","lastUpdated":1777132262000}'),o={name:"standards/content-policy.md"};function r(n,a,c,d,s,p){return t(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="内容原则" tabindex="-1">内容原则 <a class="header-anchor" href="#内容原则" aria-label="Permalink to &quot;内容原则&quot;">​</a></h1><p><code>Dao</code> 当前遵循这些基本原则：</p><h2 id="一、只优先整理无版权风险内容" tabindex="-1">一、只优先整理无版权风险内容 <a class="header-anchor" href="#一、只优先整理无版权风险内容" aria-label="Permalink to &quot;一、只优先整理无版权风险内容&quot;">​</a></h2><p>站点正文优先收录：</p><ul><li>古籍原文</li><li>古代注疏</li><li>自己撰写的原文注解</li><li>自己撰写的学习笔记与解读</li></ul><h2 id="二、现代著作只做推荐" tabindex="-1">二、现代著作只做推荐 <a class="header-anchor" href="#二、现代著作只做推荐" aria-label="Permalink to &quot;二、现代著作只做推荐&quot;">​</a></h2><p>现代学者著作、现代出版社版本、现代课程与现代文章：</p><ul><li>可以推荐</li><li>可以列书名</li><li>可以写阅读用途</li><li>不直接收录正文内容</li></ul><h2 id="三、原典与解读分层" tabindex="-1">三、原典与解读分层 <a class="header-anchor" href="#三、原典与解读分层" aria-label="Permalink to &quot;三、原典与解读分层&quot;">​</a></h2><p>每篇内容尽量区分：</p><ul><li><code>【原典层】</code></li><li><code>【解读层】</code></li></ul><p>避免让读者误把个人理解当成原典本身。</p><h2 id="四、宁可慢-不求混" tabindex="-1">四、宁可慢，不求混 <a class="header-anchor" href="#四、宁可慢-不求混" aria-label="Permalink to &quot;四、宁可慢，不求混&quot;">​</a></h2><p>如果一篇内容暂时还没有整理清楚，那就先保留骨架，后续再补。<br> 不急着为了数量而牺牲质量。</p>',14)])])}const _=e(o,[["render",r]]);export{u as __pageData,_ as default};
